"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["413100"],{566335(e){e.exports=JSON.parse('{"tag":{"label":"configuration","permalink":"/dst-api-webdocs/docs/tags/configuration","allTagsPath":"/dst-api-webdocs/docs/tags","count":25,"items":[{"id":"game-scripts/containers","title":"Containers","description":"Defines container widget configurations for various inventory containers including setup functions, item test functions, button actions, and validation functions for backpacks, chests, cookers, and specialty containers.","permalink":"/dst-api-webdocs/docs/game-scripts/containers"},{"id":"game-scripts/map/levels/forest","title":"Forest","description":"Defines all forest world generation presets, settings, and playstyle configurations for Don\'t Starve Together survival mode.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels/forest"},{"id":"game-scripts/fx","title":"Fx","description":"Defines local helper functions for animation state manipulation and a comprehensive fx table containing visual effect configurations for Don\'t Starve Together, including splash effects, transformation effects, buff effects, environmental FX, turf effects, wagpunk, slingshot, and WX78 shield animations.","permalink":"/dst-api-webdocs/docs/game-scripts/fx"},{"id":"game-scripts/gamemodes","title":"Gamemodes","description":"Central configuration and utility system for managing game modes, including built-in and mod-defined modes, their properties, and runtime queries.","permalink":"/dst-api-webdocs/docs/game-scripts/gamemodes"},{"id":"game-scripts/tools/generate_worldgenoverride","title":"Generate Worldgenoverride","description":"Generates a worldgenoverride.lua file containing current world and settings preset values and override configurations.","permalink":"/dst-api-webdocs/docs/game-scripts/tools/generate_worldgenoverride"},{"id":"game-scripts/globalvariableoverrides_pax_server","title":"Globalvariableoverrides Pax Server","description":"Sets global configuration variables for the Pax server environment, including disabling mod warnings and configuring server termination logic.","permalink":"/dst-api-webdocs/docs/game-scripts/globalvariableoverrides_pax_server"},{"id":"game-scripts/haptics","title":"Haptics","description":"Defines the HapticEffects configuration table containing all haptic feedback effect definitions for Don\'t Starve Together, organized by category including DANGER, PLAYER, ENVIRONMENT, BOSS, and UI effects.","permalink":"/dst-api-webdocs/docs/game-scripts/haptics"},{"id":"game-scripts/map/levels/lavaarena","title":"Lavaarena","description":"Defines registration data for the Lava Arena event level, including world generation overrides and settings presets.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels/lavaarena"},{"id":"game-scripts/map/levels","title":"Levels","description":"Central registry for world generation configurations, level presets, settings presets, and playstyle definitions across all game modes.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels"},{"id":"game-scripts/mixes","title":"Mixes","description":"Registers predefined audio mix configurations with the global mixer system for various game states and events.","permalink":"/dst-api-webdocs/docs/game-scripts/mixes"},{"id":"game-scripts/screens/redux/modconfigurationscreen","title":"Modconfigurationscreen","description":"Manages the UI for configuring mod settings, displaying, editing, and persisting mod configuration options.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/modconfigurationscreen"},{"id":"game-scripts/modindex","title":"Modindex","description":"Manages mod loading, state, dependencies, configuration, and compatibility for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/modindex"},{"id":"game-scripts/screens/modsscreen","title":"Modsscreen","description":"Manages the in-game mod configuration screen, including mod list rendering, enable/disable toggling, updates, configuration, and applying changes with proper cleanup and reload workflows.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/modsscreen"},{"id":"game-scripts/widgets/modstab","title":"ModsTab","description":"Manages the mod list UI in the server creation screen, including listing, enabling/disabling, configuring, updating, and displaying mod details for client and server mods.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/modstab"},{"id":"game-scripts/prefabswaps","title":"Prefabswaps","description":"Manages configurable prefab substitutions used during world generation, supporting primary/non-primary variants, location-based exclusions, and customization-controlled prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabswaps"},{"id":"game-scripts/map/levels/quagmire","title":"Quagmire","description":"Defines the level configuration and generation presets for the Quagmire event map.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels/quagmire"},{"id":"game-scripts/recipes","title":"Recipes","description":"This file defines the complete crafting recipe registry for Don\'t Starve Together, registering all character-specific items, structures, tools, consumables, event items, and deconstruction recipes using Recipe2() and Ingredient() functions with technology tier requirements, ingredient costs, and validation callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/recipes"},{"id":"game-scripts/prefabs/rift_portal_defs","title":"Rift Portal Defs","description":"Defines configuration templates and utility functions for rift portal prefabs, including fallback implementations and affinity constants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rift_portal_defs"},{"id":"game-scripts/widgets/redux/serversettingstab","title":"Serversettingstab","description":"Manages the server configuration UI tab in the server creation screen, including server name, description, password, privacy, game mode, player count, and related settings.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/serversettingstab"},{"id":"game-scripts/prefabs/skilltree_wilson","title":"Skilltree Wilson","description":"Defines Wilson\'s skill tree data structure, including skill nodes, layout orders, and activation logic for the character progression system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skilltree_wilson"},{"id":"game-scripts/prefabs/skilltree_wortox","title":"Skilltree Wortox","description":"Defines Wortox\'s skill tree configuration including skill definitions for nice, naughty, neutral, and allegiance paths with activation/deactivation callbacks, lock conditions, UI button decorations, and utility functions for panflute timer management, soul jar updates, reviver item linking, and lunar resistance setup.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skilltree_wortox"},{"id":"game-scripts/skin_affinity_info","title":"Skin Affinity Info","description":"A static configuration table mapping character names to their associated skin prefab identifiers for affinity tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/skin_affinity_info"},{"id":"game-scripts/tilemanager","title":"Tilemanager","description":"Central registry and validation system for defining and configuring in-game ground tiles, minimap tiles, falloff textures, and ground creep assets.","permalink":"/dst-api-webdocs/docs/game-scripts/tilemanager"},{"id":"game-scripts/tuning","title":"Tuning","description":"Defines and initializes the global TUNING table containing all gameplay constants and configuration values for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/tuning"},{"id":"game-scripts/worldsettings_overrides","title":"Worldsettings Overrides","description":"Provides tuning override functions that adjust game difficulty settings for wildlife, weather, events, regrowth, and world mechanics by modifying global TUNING values or dispatching world state events.","permalink":"/dst-api-webdocs/docs/game-scripts/worldsettings_overrides"}],"unlisted":false}}')}}]);